<?php declare(strict_types=1); namespace App\Services\Attendance; use App\Enums\TeachingJournalStatus; use App\Models\StudentAttendance; use App\Models\TeachingAssignment; use App\Models\TeachingJournal; use App\Services\ActivityLogger; use Illuminate\Support\Facades\DB; use Illuminate\Validation\ValidationException;
class TeachingJournalService{public function __construct(private ActivityLogger $logger){} public function save(TeachingAssignment $ta,array $data,array $students=[]):TeachingJournal{return DB::transaction(function()use($ta,$data,$students){if(auth()->user()?->employee && auth()->user()->employee->id!==$ta->employee_id)throw ValidationException::withMessages(['teaching_assignment_id'=>'Guru tidak ditugaskan.']); $journal=TeachingJournal::updateOrCreate(['id'=>$data['id']??null],$data+['teaching_assignment_id'=>$ta->id,'employee_id'=>$ta->employee_id,'subject_id'=>$ta->subject_id,'classroom_id'=>$ta->classroom_id,'academic_year_id'=>$ta->academic_year_id,'semester_id'=>$ta->semester_id]); if($students){$sync=[];foreach($students as $id=>$r){$sync[$id]=['status'=>$r['status'],'notes'=>$r['notes']??null];}$journal->students()->sync($sync);} else {$atts=StudentAttendance::where('classroom_id',$ta->classroom_id)->whereDate('attendance_date',$journal->journal_date)->get(); if($atts->isNotEmpty())$journal->students()->sync($atts->mapWithKeys(fn($a)=>[$a->student_id=>['status'=>$a->status->value,'notes'=>$a->notes]])->all());} $this->logger->log('teaching-journal.saved',$journal,[],$journal->toArray()); return $journal;});} public function submit(TeachingJournal $j):void{if($j->status!==TeachingJournalStatus::Draft && $j->status!==TeachingJournalStatus::Rejected)throw ValidationException::withMessages(['status'=>'Jurnal tidak dapat dikirim.']);$j->update(['status'=>TeachingJournalStatus::Submitted,'submitted_at'=>now()]);$this->logger->log('teaching-journal.submitted',$j);} public function verify(TeachingJournal $j):void{$j->update(['status'=>TeachingJournalStatus::Verified,'verified_by'=>auth()->id(),'verified_at'=>now()]);$this->logger->log('teaching-journal.verified',$j);} public function reject(TeachingJournal $j,string $reason):void{$j->update(['status'=>TeachingJournalStatus::Rejected,'verified_by'=>auth()->id(),'verified_at'=>now(),'rejection_reason'=>$reason]);$this->logger->log('teaching-journal.rejected',$j,[],[],$reason);}}
